let line = String(msg.payload || '').trim();
if (!line.startsWith('MEGA|STATUS|')) return null;

const parts = line.split('|');
const obj = {};
for (let i = 2; i < parts.length; i++) {
    const part = parts[i];
    const eq = part.indexOf('=');
    if (eq > 0) {
        const key = part.substring(0, eq);
        const value = part.substring(eq + 1);
        obj[key] = value;
    }
}

const stateMap = {
    SEARCHING: 'Araniyor',
    PAUSED: 'Duraklatildi',
    WAIT_ARM: 'Robot Bekliyor',
    STOPPED: 'Durdu',
    IDLE: 'Beklemede',
    RUN: 'Calisiyor',
    STOP: 'Durdu',
    ERROR: 'Hata',
    MEASURING: 'Olcum',
    BUSY: 'Calisiyor',
    DONE: 'Tamamlandi'
};

return [
    { payload: obj.AUTO === '1' ? 'Otomatik' : 'Manuel' },
    { payload: stateMap[obj.STATE] || obj.STATE || '-' },
    { payload: stateMap[obj.CONVEYOR] || obj.CONVEYOR || '-' },
    { payload: stateMap[obj.ROBOT] || obj.ROBOT || '-' },
    { payload: obj.LAST || '-' },
    { payload: obj.DIR || '-' },
    { payload: obj.PWM || '-' },
    { payload: obj.TRAVEL_MS || '-' },
    { payload: obj.LIM22 === '1' ? 'Basili' : 'Acik' },
    { payload: obj.LIM23 === '1' ? 'Basili' : 'Acik' },
    { payload: obj.STEP === '1' ? 'Calisiyor' : 'Durdu' },
    { payload: obj.STEP_HOLD === '1' ? 'Aktif' : 'Pasif' },
    { payload: obj.STEP_US || '-' },
    { payload: obj.QUEUE || '0' },
    { payload: obj.STOP_REQ === '1' ? 'Var' : 'Yok' }
];

let logs = flow.get('logBuffer') || [];
let line = String(msg.payload || '').trim();

if (line.length > 0) {
    logs.push(line);
}

const MAX_LINES = 200;
if (logs.length > MAX_LINES) {
    logs = logs.slice(logs.length - MAX_LINES);
}

flow.set('logBuffer', logs);
msg.payload = logs.join('\n');
return msg;

let counts = flow.get('counts') || {
    red: 0,
    yellow: 0,
    blue: 0
};

const line = String(msg.payload || '').trim();

if (line === '__reset_counts__') {
    counts = { red: 0, yellow: 0, blue: 0 };
} else if (line.includes('QUEUE=ENQ')) {
    const parts = line.split('|');
    const obj = {};
    for (let i = 0; i < parts.length; i++) {
        const eq = parts[i].indexOf('=');
        if (eq > 0) obj[parts[i].slice(0, eq)] = parts[i].slice(eq + 1);
    }

    if (obj.COLOR === 'KIRMIZI') counts.red++;
    else if (obj.COLOR === 'SARI') counts.yellow++;
    else if (obj.COLOR === 'MAVI') counts.blue++;
}

flow.set('counts', counts);

return [
    { payload: counts.red },
    { payload: counts.yellow },
    { payload: counts.blue }
];

let now = new Date();

let day = String(now.getDate()).padStart(2, '0');
let month = String(now.getMonth() + 1).padStart(2, '0');
let year = now.getFullYear();

let hour = String(now.getHours()).padStart(2, '0');
let minute = String(now.getMinutes()).padStart(2, '0');
let second = String(now.getSeconds()).padStart(2, '0');
let ms = String(now.getMilliseconds()).padStart(3, '0');

let timestamp = `${day}.${month}.${year} ${hour}:${minute}:${second}.${ms}`;

msg.payload = `[${timestamp}] ${msg.payload}\n`;
msg.filename = `C:\\Users\\acer\\Documents\\.CODE\\codex\\MES\\logs\\log_${year}-${month}-${day}.txt`;

return msg;

let line = String(msg.payload || '').trim();
if (!line.startsWith('ESP32|BRIDGE|')) return null;

const parts = line.split('|');
const obj = {};
for (let i = 2; i < parts.length; i++) {
    const eq = parts[i].indexOf('=');
    if (eq > 0) obj[parts[i].slice(0, eq)] = parts[i].slice(eq + 1);
}

const link = (obj.WIFI === '1' && obj.MQTT === '1') ? 'Online' : 'Degrede';
return [
    { payload: link },
    { payload: obj.QUEUE || '0' },
    { payload: obj.DROP_UART || '0' },
    { payload: obj.DROP_PUB || '0' }
];

let payload = msg.payload;
if (typeof payload === 'string') {
    try { payload = JSON.parse(payload); } catch (err) { return null; }
}
const stateMap = { starting: 'Basliyor', running: 'Calisiyor', stopped: 'Durdu' };
return [
    { payload: stateMap[payload.state] || payload.state || '-' },
    { payload: payload.fps != null ? String(payload.fps) : '-' }
];

let payload = msg.payload;
if (typeof payload === 'string') {
    try { payload = JSON.parse(payload); } catch (err) { return null; }
}
return [
    { payload: payload.active_tracks != null ? String(payload.active_tracks) : '0' },
    { payload: payload.pending_tracks != null ? String(payload.pending_tracks) : '0' },
    { payload: payload.total_crossings != null ? String(payload.total_crossings) : '0' }
];

let payload = msg.payload;
if (typeof payload === 'string') {
    try { payload = JSON.parse(payload); } catch (err) { return null; }
}
let stamp = '-';
if (payload.timestamp) {
    const dt = new Date(payload.timestamp);
    stamp = Number.isNaN(dt.getTime()) ? String(payload.timestamp) : dt.toLocaleTimeString('tr-TR', { hour12: false });
}
return { payload: stamp };

const colorMap = { red: 'red', yellow: 'yellow', blue: 'blue', kirmizi: 'red', sari: 'yellow', mavi: 'blue' };
let payload = msg.payload;
if (typeof payload === 'string') {
    try { payload = JSON.parse(payload); } catch (err) { return [null, null]; }
}
const rawColor = String(payload.color_name || payload.label || payload.profile_id || '').trim().toLowerCase();
const color = colorMap[rawColor] || rawColor;
const notes = [];
if (payload.profile_id) notes.push('profile=' + payload.profile_id);
if (payload.frame_index != null) notes.push('frame=' + payload.frame_index);
const structured = {
    event_time: payload.timestamp || new Date().toISOString(),
    item_id: '',
    measure_id: '',
    source: 'vision',
    event_type: payload.event || 'vision_event',
    color,
    decision_source: 'vision',
    queue_depth: '',
    mega_state: '',
    raw_r: '',
    raw_g: '',
    raw_b: '',
    confidence: '',
    vision_track_id: payload.track_id != null ? String(payload.track_id) : '',
    notes: notes.join(';'),
    review_required: false,
    travel_ms: ''
};
const compare = payload.event === 'line_crossed' ? { source: 'vision', color } : null;
return [{ payload: structured }, compare ? { payload: compare } : null];

const colorMap = { KIRMIZI: 'red', SARI: 'yellow', MAVI: 'blue', BOS: 'empty', BELIRSIZ: 'uncertain' };
const line = String(msg.payload || '').trim();
if (!line.startsWith('MEGA|')) return [null, null, null];

const parts = line.split('|');
const moduleName = parts[1] || '';
const obj = {};
for (let i = 2; i < parts.length; i++) {
    const eq = parts[i].indexOf('=');
    if (eq > 0) obj[parts[i].slice(0, eq)] = parts[i].slice(eq + 1);
}

const normalizeColor = (value) => {
    const raw = String(value || '').trim().toUpperCase();
    return colorMap[raw] || raw.toLowerCase();
};
const normalizeId = (value) => {
    const text = String(value == null ? '' : value).trim();
    return (!text || text === '0' || text === '-') ? '' : text;
};
const eventTime = new Date().toISOString();
let structured = null;
let compare = null;

if (moduleName === 'TCS3200' && obj.STATE === 'MEASURING' && obj.FINAL) {
    const notes = [];
    if (obj.SEARCH_HINT) notes.push('search_hint=' + obj.SEARCH_HINT);
    if (obj.REVIEW != null) notes.push('review=' + obj.REVIEW);
    if (obj.VOTE_Y != null) notes.push('vote_y=' + obj.VOTE_Y);
    if (obj.VOTE_SECOND != null) notes.push('vote_second=' + obj.VOTE_SECOND);
    structured = {
        event_time: eventTime,
        item_id: normalizeId(obj.ITEM_ID),
        measure_id: normalizeId(obj.MEASURE_ID),
        source: 'mega',
        event_type: 'measurement_decision',
        color: normalizeColor(obj.FINAL),
        decision_source: obj.FINAL_SOURCE || '',
        queue_depth: obj.PENDING || '',
        mega_state: obj.STATE || '',
        raw_r: obj.MED_R || '',
        raw_g: obj.MED_G || '',
        raw_b: obj.MED_B || '',
        confidence: obj.CONF || '',
        vision_track_id: '',
        notes: notes.join(';'),
        review_required: obj.REVIEW === '1',
        travel_ms: ''
    };
} else if (moduleName === 'AUTO' && obj.QUEUE === 'ENQ') {
    structured = {
        event_time: eventTime,
        item_id: normalizeId(obj.ITEM_ID),
        measure_id: normalizeId(obj.MEASURE_ID),
        source: 'mega',
        event_type: 'queue_enq',
        color: normalizeColor(obj.COLOR),
        decision_source: obj.DECISION_SOURCE || '',
        queue_depth: obj.PENDING || '',
        mega_state: obj.STATE || 'QUEUE',
        raw_r: '',
        raw_g: '',
        raw_b: '',
        confidence: '',
        vision_track_id: '',
        notes: obj.REVIEW != null ? ('review=' + obj.REVIEW) : '',
        review_required: obj.REVIEW === '1',
        travel_ms: obj.TRAVEL_MS || ''
    };
    compare = { source: 'mega', color: structured.color };
} else if (moduleName === 'AUTO' && obj.EVENT === 'ARM_POSITION_REACHED') {
    structured = {
        event_time: eventTime,
        item_id: normalizeId(obj.ITEM_ID),
        measure_id: normalizeId(obj.MEASURE_ID),
        source: 'mega',
        event_type: 'arm_position_reached',
        color: normalizeColor(obj.COLOR),
        decision_source: obj.DECISION_SOURCE || '',
        queue_depth: '',
        mega_state: obj.STATE || '',
        raw_r: '',
        raw_g: '',
        raw_b: '',
        confidence: '',
        vision_track_id: '',
        notes: obj.REVIEW != null ? ('review=' + obj.REVIEW) : '',
        review_required: obj.REVIEW === '1',
        travel_ms: ''
    };
} else if (moduleName === 'AUTO' && obj.EVENT === 'PICKPLACE_DONE') {
    structured = {
        event_time: eventTime,
        item_id: normalizeId(obj.ITEM_ID),
        measure_id: normalizeId(obj.MEASURE_ID),
        source: 'mega',
        event_type: 'pickplace_done',
        color: normalizeColor(obj.COLOR),
        decision_source: obj.DECISION_SOURCE || '',
        queue_depth: obj.PENDING || obj.QUEUE || '',
        mega_state: obj.STATE || '',
        raw_r: '',
        raw_g: '',
        raw_b: '',
        confidence: '',
        vision_track_id: '',
        notes: obj.REVIEW != null ? ('review=' + obj.REVIEW) : '',
        review_required: obj.REVIEW === '1',
        travel_ms: ''
    };
}

if (!structured) return [null, null, null];
return [{ payload: structured }, { payload: structured }, compare ? { payload: compare } : null];

const cols = ['event_time','item_id','measure_id','source','event_type','color','decision_source','queue_depth','mega_state','raw_r','raw_g','raw_b','confidence','vision_track_id','notes'];
const filename = 'C:\\Users\\acer\\Documents\\.CODE\\codex\\MES\\production_events.csv';
const headerKey = 'header:' + filename;
const csv = (value) => {
    const text = value == null ? '' : String(value);
    if (text.includes(',') || text.includes('"') || text.includes('\n')) return '"' + text.replace(/"/g, '""') + '"';
    return text;
};
const row = cols.map((key) => csv(msg.payload[key] ?? '')).join(',') + '\n';
msg.filename = filename;
msg.payload = flow.get(headerKey) ? row : (cols.join(',') + '\n' + row);
flow.set(headerKey, true);
return msg;

const event = msg.payload || {};
if (!event.event_type) return null;
const key = event.item_id || (event.measure_id ? 'measure:' + event.measure_id : '');
if (!key) return null;
const state = flow.get('productionCompletedState') || {};
const entry = state[key] || {
    item_id: event.item_id || '',
    measure_id: event.measure_id || '',
    detected_at: '',
    completed_at: '',
    color: '',
    travel_ms: '',
    decision_source: '',
    review_required: false
};

if (event.item_id) entry.item_id = event.item_id;
if (event.measure_id) entry.measure_id = event.measure_id;
if (event.color) entry.color = event.color;
if (event.decision_source) entry.decision_source = event.decision_source;
entry.review_required = Boolean(entry.review_required || event.review_required);
if (event.travel_ms) entry.travel_ms = event.travel_ms;

if (event.event_type === 'queue_enq' && event.event_time) {
    entry.detected_at = event.event_time;
}

if (event.event_type !== 'pickplace_done') {
    state[key] = entry;
    flow.set('productionCompletedState', state);
    return null;
}

entry.completed_at = event.event_time || '';
const startedAt = Date.parse(entry.detected_at || '');
const finishedAt = Date.parse(entry.completed_at || '');
let cycleMs = '';
if (!Number.isNaN(startedAt) && !Number.isNaN(finishedAt) && finishedAt >= startedAt) {
    cycleMs = String(finishedAt - startedAt);
}

const payload = {
    item_id: entry.item_id || event.item_id || '',
    detected_at: entry.detected_at || '',
    completed_at: entry.completed_at || '',
    color: entry.color || event.color || '',
    status: entry.review_required ? 'COMPLETED_REVIEW' : 'COMPLETED',
    travel_ms: entry.travel_ms || '',
    cycle_ms: cycleMs,
    decision_source: entry.decision_source || event.decision_source || ''
};

delete state[key];
flow.set('productionCompletedState', state);
msg.payload = payload;
return msg;

const cols = ['item_id','detected_at','completed_at','color','status','travel_ms','cycle_ms','decision_source'];
const filename = 'C:\\Users\\acer\\Documents\\.CODE\\codex\\MES\\production_completed.csv';
const headerKey = 'header:' + filename;
const csv = (value) => {
    const text = value == null ? '' : String(value);
    if (text.includes(',') || text.includes('"') || text.includes('\n')) return '"' + text.replace(/"/g, '""') + '"';
    return text;
};
const row = cols.map((key) => csv(msg.payload[key] ?? '')).join(',') + '\n';
msg.filename = filename;
msg.payload = flow.get(headerKey) ? row : (cols.join(',') + '\n' + row);
flow.set(headerKey, true);
return msg;

const update = msg.payload || {};
const allowed = ['red', 'yellow', 'blue'];
if (!allowed.includes(update.color)) return null;
const stats = flow.get('megaVisionCompare') || {
    mega: { red: 0, yellow: 0, blue: 0 },
    vision: { red: 0, yellow: 0, blue: 0 }
};
if (update.source === 'mega') stats.mega[update.color]++;
if (update.source === 'vision') stats.vision[update.color]++;
flow.set('megaVisionCompare', stats);
const diff = {
    red: stats.mega.red - stats.vision.red,
    yellow: stats.mega.yellow - stats.vision.yellow,
    blue: stats.mega.blue - stats.vision.blue
};
const yellowAlarm = Math.abs(diff.yellow) > 1
    ? 'ALARM | mega=' + stats.mega.yellow + ' vision=' + stats.vision.yellow
    : 'Normal | mega=' + stats.mega.yellow + ' vision=' + stats.vision.yellow;
return [
    { payload: 'K:' + stats.mega.red + ' S:' + stats.mega.yellow + ' M:' + stats.mega.blue },
    { payload: 'K:' + stats.vision.red + ' S:' + stats.vision.yellow + ' M:' + stats.vision.blue },
    { payload: 'K:' + diff.red + ' S:' + diff.yellow + ' M:' + diff.blue },
    { payload: yellowAlarm }
];
